package com.securestack.report;import org.springframework.stereotype.Service;import com.openhtmltopdf.pdfboxout.PdfRendererBuilder;import com.securestack.service.ScanService;import java.io.*;import java.util.*;@Service public class ReportService{private final ScanService scans;public ReportService(ScanService s){scans=s;}public byte[] pdf(UUID id){var r=scans.get(id);StringBuilder h=new StringBuilder("<html><body style='font-family:sans-serif'><h1>SecureStack AI Security Review Report</h1>");h.append("<p><b>Scan:</b> ").append(r.name()).append("</p><p><b>Risk score:</b> ").append(r.riskScore()).append(" ("+r.riskLevel()+")</p><h2>Executive Summary</h2><p>").append(r.executiveSummary()).append("</p><h2>Severity Breakdown</h2><p>").append(r.severityCounts()).append("</p><h2>Findings</h2><table border='1' cellspacing='0' cellpadding='5'><tr><th>Severity</th><th>Title</th><th>File</th><th>Recommendation</th></tr>");r.findings().forEach(f->h.append("<tr><td>").append(f.severity()).append("</td><td>").append(esc(f.title())).append("</td><td>").append(esc(f.fileName())).append(":"+f.lineNumber()).append("</td><td>").append(esc(f.recommendation())).append("</td></tr>"));h.append("</table><h2>Methodology and limitations</h2><p>Static rules, dependency/config heuristics, and mock AI summaries. This is not a replacement for professional security review.</p><footer>SecureStack AI</footer></body></html>");try(ByteArrayOutputStream out=new ByteArrayOutputStream()){new PdfRendererBuilder().withHtmlContent(h.toString(),null).toStream(out).run();return out.toByteArray();}catch(Exception e){throw new RuntimeException("Report generation failed",e);}}String esc(String s){return s==null?"":s.replace("&","&amp;").replace("<","&lt;").replace(">","&gt;");}}
